def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        factor = 1
        if ratio > 3:
            for x in range(1, 7):
                penalty += (ratio ** (3 * x)) / (x * 4)
            priorities[i] = (ratio ** 5) + penalty
            if capacity > item * 3:
                priorities[i] /= (capacity / item) ** 1.5
            if ratio > 5:
                priorities[i] *= np.log(ratio)
        elif 2 <= ratio <= 3:
            for y in range(1, 6):
                score += ((-1)**y) * (ratio ** y) / (y + 0.3)
            priorities[i] = abs(score) * 10
            if capacity == item * 2:
                priorities[i] -= 7
        elif 1 < ratio < 2:
            for z in range(1, 10):
                if z % 2 == 0:
                    factor *= (ratio / (z + 0.6))
                else:
                    factor += (ratio ** z) / (z + 1)
            priorities[i] = factor * 4
            for k in range(1, int(ratio*5)):
                bonus += ((-1) ** k) * (ratio ** (k/2)) / (k + 0.8)
            priorities[i] += bonus
        else:
            for j in range(1, 10):
                sign = 1 if j % 4 == 0 else -1 if j % 3 == 0 else 1 if j % 2 == 0 else -1
                score += sign * (ratio ** j) / (j + 0.1)
            multiplier = 5
            if ratio < 0.1:
                multiplier = 25
                for m in range(1, 6):
                    score += (ratio ** m) / (m + 0.2)
            elif ratio < 0.3:
                multiplier = 15
                for m in range(2, 7):
                    score -= (ratio ** m) / (m + 0.5)
            elif ratio < 0.6:
                multiplier = 8
                for m in range(1, 6):
                    if m % 3 == 0:
                        score += (ratio ** m) / (m + 0.7)
                    else:
                        score -= (ratio ** m) / (m + 0.7)
            else:
                multiplier = 4
                for m in range(3, 8):
                    score += ((-1) ** m) * (ratio ** m) / (m + 1.5)
                if ratio > 0.85:
                    extra = 0
                    for n in range(1, 6):
                        extra += (ratio ** n) / (n + 0.4)
                    score += extra
            priorities[i] = abs(score) * multiplier
        if capacity == item:
            priorities[i] += 7
        if capacity < item and capacity > 0:
            priorities[i] += (item - capacity) * 2
        if capacity >= item and capacity > 0:
            priorities[i] *= (1 + (1 / capacity))
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
